bjectOutputStream oos=new ObjectOutputStream(new FileOutputStream(&quot;ser.bin&quot;));        oos.writeObject(obj);    &#125;    public static Object unserialize(String filename) throws Exception &#123;        ObjectInputStream ois=new ObjectInputStream(new FileInputStream(filename));        Object obj=ois.readObject();        return obj;    &#125;&#125;
