&lt;dependency&gt;          &lt;groupId&gt;org.aspectj&lt;/groupId&gt;          &lt;artifactId&gt;aspectjweaver&lt;/artifactId&gt;          &lt;version&gt;1.9.19&lt;/version&gt;      &lt;/dependency&gt;
AOP同样可以完全使用注解完成，在这里就全部使用注解包括beans的配置文件，我也一并用注解代替，但是首先先介绍一下单纯用注解实现AOP而不省去配置文件的做法：
&lt;?xml version=&quot;1.0&quot; encoding=&quot;UTF-8&quot;?&gt;&lt;beans xmlns=&quot;http://www.springframework.org/schema/beans&quot;       xmlns:p=&quot;http://www.springframework.org/schema/p&quot; xmlns:xsi=&quot;http://www.w3.org/2001/XMLSchema-instance&quot;       xmlns:context=&quot;http://www.springframework.org/schema/context&quot;       xmlns:aop=&quot;http://www.springframework.org/schema/aop&quot;       xsi:schemaLocation=&quot;http://www.springframework.org/schema/beans     http://www.springframework.org/schema/beans/spring-beans-4.1.xsd     http://www.springframework.org/schema/context     http://www.springframework.org/schema/context/spring-context-4.1.xsd     http://www.springframework.org/schema/aop http://www.springframework.org/schema/aop/spring-aop-4.1.xsd&quot;&gt;    &lt;bean id=&quot;simple&quot; class=&quot;com.boogipop.service.SimpleImpl&quot;/&gt;&lt;!--  需要注册bean --&gt;    &lt;bean id=&quot;selfcut&quot; class=&quot;com.boogipop.cutface.Selfcut&quot;/&gt;&lt;!-- 开启注解扫描 --&gt;    &lt;aop:aspectj-autoproxy/&gt;&lt;/beans&gt;
package com.boogipop.cutface;import org.aspectj.lang.JoinPoint;import org.aspectj.lang.ProceedingJoinPoint;import org.aspectj.lang.annotation.*;import org.aspectj.lang.annotation.After;import org.aspectj.lang.annotation.Before;//定义切面类@Aspectpublic class Selfcut &#123;    @Before(&quot;execution(* com.boogipop.service.SimpleImpl.*(..))&quot;)    public void before()&#123;        System.out.println(&quot;===self before===&quot;);    &#125;    @After(&quot;execution(* com.boogipop.service.SimpleImpl.*(..))&quot;)    public void after()&#123;        System.out.println(&quot;===self after===&quot;);    &#125;    @Around(&quot;execution(* com.boogipop.service.SimpleImpl.*(..))&quot;)    public void around(ProceedingJoinPoint jp) throws Throwable &#123;        System.out.println(&quot;环绕前&quot;);//        执行切入点的方法        Object proceed = jp.proceed();        System.out.println(&quot;环绕后&quot;);//        获取签名        System.out.println(jp.getSignature());    &#125;    @AfterReturning(&quot;execution(* com.boogipop.service.SimpleImpl.*(..))&quot;)    public void afterreturn()&#123;        System.out.println(&quot;after return&quot;);    &#125;&#125;
顺序为环绕前-&gt;执行前-&gt;方法执行-&gt;返回后通知-&gt;执行后-&gt;环绕执行后（这里是spring6的顺序，spring5貌似不一样，不过问题不大），这就是注解和xml结合的使用，下面我将尝试全注解实现：
package com.boogipop.config;import com.boogipop.cutface.Selfcut;import com.boogipop.service.CURD;import com.boogipop.service.SimpleImpl;import org.springframework.context.annotation.Bean;import org.springframework.context.annotation.ComponentScan;import org.springframework.context.annotation.Configuration;import org.springframework.context.annotation.EnableAspectJAutoProxy;@Configuration@ComponentScan(&quot;com.boogipop&quot;)@EnableAspectJAutoProxy //开启aop注解支持public class Config &#123;    @Bean    public Selfcut selfcut()&#123;        return new Selfcut();    &#125;    @Bean    public CURD curd()&#123;        return new SimpleImpl();    &#125;&#125;
package com.boogipop.cutface;import org.aspectj.lang.JoinPoint;import org.aspectj.lang.ProceedingJoinPoint;import org.aspectj.lang.annotation.*;import org.aspectj.lang.annotation.After;import org.aspectj.lang.annotation.Before;//定义切面类@Aspectpublic class Selfcut &#123;    @Before(&quot;execution(* com.boogipop.service.SimpleImpl.*(..))&quot;)    public void before()&#123;        System.out.println(&quot;===self before===&quot;);    &#125;    @After(&quot;execution(* com.boogipop.service.SimpleImpl.*(..))&quot;)    public void after()&#123;        System.out.println(&quot;===self after===&quot;);    &#125;    @Around(&quot;execution(* com.boogipop.service.SimpleImpl.*(..))&quot;)    public void around(ProceedingJoinPoint jp) throws Throwable &#123;        System.out.println(&quot;环绕前&quot;);//        执行切入点的方法        Object proceed = jp.proceed();        System.out.println(&quot;环绕后&quot;);//        获取签名        System.out.println(jp.getSignature());    &#125;    @AfterReturning(&quot;execution(* com.boogipop.service.SimpleImpl.*(..))&quot;)    public void afterreturn()&#123;        System.out.println(&quot;after return&quot;);    &#125;&#125;
