import com.boogipop.mapper.UserMapper;import com.boogipop.pojo.User;import com.boogipop.utils.MybatisUtil;import org.apache.ibatis.session.SqlSession;import org.junit.Test;import java.util.List;public class Exec &#123;    @Test    public void selectall()&#123;        SqlSession sqlsession = MybatisUtil.getSqlsession();        UserMapper mapper = sqlsession.getMapper(UserMapper.class);        List&lt;User&gt; getuserlist = mapper.getuserlist();        for (User user : getuserlist) &#123;            System.out.println(user);        &#125;        sqlsession.close();    &#125;&#125;
