ty name=&quot;configLocation&quot; value=&quot;classpath:mybatis-config.xml&quot;/&gt;        &lt;property name=&quot;mapperLocations&quot; value=&quot;classpath:com/boogipop/mapper/UserMapper.xml&quot;/&gt;    &lt;/bean&gt;    &lt;bean class=&quot;org.mybatis.spring.SqlSessionTemplate&quot; id=&quot;sqlsession&quot;&gt;&lt;!--只能使用构造器创建，因为没有set方法--&gt;        &lt;constructor-arg index=&quot;0&quot; ref=&quot;sqlsessionfactory&quot;/&gt;    &lt;/bean&gt;    &lt;bean id=&quot;userMapper2&quot; class=&quot;com.boogipop.mapper.UserMapperImpl2&quot;&gt;        &lt;property name=&quot;sqlSessionFactory&quot; ref=&quot;sqlsessionfactory&quot;/&gt;    &lt;/bean&gt;    &lt;!--加载mapper包中的所有接口，通过sqlSessionFactory获取sqlSession对象，然后创建所有的dao接口并存储在Spring容器中--&gt;    &lt;bean class=&quot;org.mybatis.spring.mapper.MapperScannerConfigurer&quot;&gt;&lt;!--                                                       这里的value和上面sqlsessionfactory的id对应                     --&gt;        &lt;property name=&quot;sqlSessionFactoryBeanName&quot; value=&quot;sqlsessionfactory&quot;/&gt;        &lt;property name=&quot;basePackage&quot; value=&quot;com.boogipop.mapper&quot;/&gt;    &lt;/bean&gt;&lt;!--    配置声明式事务--&gt;    &lt;bean class=&quot;org.springframework.jdbc.datasource.DataSourceTransactionManager&quot; id=&quot;transactionManager&quot;&gt;        &lt;property name=&quot;dataSource&quot; ref=&quot;datasource&quot;/&gt;    &lt;/bean&gt;&lt;!--    结合AOP事务织入--&gt;    &lt;tx:advice id=&quot;txadvice&quot; transaction-manager=&quot;transactionManager&quot;&gt;&lt;!--        给方法配置事务--&gt;       &lt;tx:attributes&gt;           &lt;tx:method name=&quot;getuserlist&quot; propagation=&quot;REQUIRED&quot;/&gt;           &lt;tx:method name=&quot;getuserbyname&quot; propagation=&quot;REQUIRED&quot;/&gt;       &lt;/tx:attributes&gt;    &lt;/tx:advice&gt;&lt;!--    aop切面--&gt;    &lt;aop:config&gt;&lt;!--        切入点--&gt;        &lt;aop:pointcut id=&quot;point&quot; expression=&quot;execution(* com.boogipop.mapper..*.*(..))&quot;/&gt;&lt;!--        切入方法--&gt;        &lt;aop:advisor advice-ref=&quot;txadvice&quot; pointcut-ref=&quot;point&quot;/&gt;    &lt;/aop:config&gt;&lt;/beans&gt;
