package com.boogipop.filters;import jakarta.servlet.*;import java.io.IOException;public class EncodingFilter implements Filter &#123;    @Override    public void init(FilterConfig filterConfig) throws ServletException &#123;        Filter.super.init(filterConfig);    &#125;    @Override    public void doFilter(ServletRequest servletRequest, ServletResponse servletResponse, FilterChain filterChain) throws IOException, ServletException &#123;        servletRequest.setCharacterEncoding(&quot;utf-8&quot;);        servletResponse.setCharacterEncoding(&quot;utf-8&quot;);        filterChain.doFilter(servletRequest,servletResponse);    &#125;    @Override    public void destroy() &#123;        Filter.super.destroy();    &#125;&#125;
package com.boogipop.filters;import jakarta.servlet.*;import jakarta.servlet.http.HttpServletRequest;import jakarta.servlet.http.HttpServletRequestWrapper;import jakarta.servlet.http.HttpServletResponse;import java.io.IOException;import java.io.UnsupportedEncodingException;import java.util.Map;public class SpecialFilter implements Filter &#123;    @Override    public void init(FilterConfig filterConfig) throws ServletException &#123;        Filter.super.init(filterConfig);    &#125;    @Override    public void doFilter(ServletRequest request, ServletResponse response, FilterChain filterChain) throws IOException, ServletException &#123;        //处理response的字符编码        HttpServletResponse myResponse=(HttpServletResponse) response;        myResponse.setContentType(&quot;text/html;charset=UTF-8&quot;);        // 转型为与协议相关对象        HttpServletRequest httpServletRequest = (HttpServletRequest) request;        // 对request包装增强        HttpServletRequest myrequest = new MyRequest(httpServletRequest);        filterChain.doFilter(myrequest, response);    &#125;    @Override    public void destroy() &#123;        Filter.super.destroy();    &#125;    //自定义request对象，HttpServletRequest的包装类    class MyRequest extends HttpServletRequestWrapper &#123;        private HttpServletRequest request;        //是否编码的标记        private boolean hasEncode;        //定义一个可以传入HttpServletRequest对象的构造函数，以便对其进行装饰        public MyRequest(HttpServletRequest request) &#123;            super(request);// super必须写            this.request = request;        &#125;        // 对需要增强方法 进行覆盖        @Override        public Map getParameterMap() &#123;            // 先获得请求方式            String method = request.getMethod();            if (method.equalsIgnoreCase(&quot;post&quot;)) &#123;                // post请求                try &#123;                    // 处理post乱码                    request.setCharacterEncoding(&quot;utf-8&quot;);                    return request.getParameterMap();                &#125; catch (UnsupportedEncodingException e) &#123;                    e.printStackTrace();                &#125;            &#125; else if (method.equalsIgnoreCase(&quot;get&quot;)) &#123;                // get请求                Map&lt;String, String[]&gt; parameterMap = request.getParameterMap();                if (!hasEncode) &#123; // 确保get手动编码逻辑只运行一次                    for (String parameterName : parameterMap.keySet()) &#123;                        String[] values = parameterMap.get(parameterName);                        if (values != null) &#123;                            for (int i = 0; i &lt; values.length; i++) &#123;                                try &#123;                                    // 处理get乱码                                    values[i] = new String(values[i]                                            .getBytes(&quot;ISO-8859-1&quot;), &quot;utf-8&quot;);                                &#125; catch (UnsupportedEncodingException e) &#123;                                    e.printStackTrace();                                &#125;                            &#125;                        &#125;                    &#125;                    hasEncode = true;                &#125;                return parameterMap;            &#125;            return super.getParameterMap();        &#125;        //取一个值        @Override        public String getParameter(String name) &#123;            Map&lt;String, String[]&gt; parameterMap = getParameterMap();            String[] values = parameterMap.get(name);            if (values == null) &#123;                return null;            &#125;            return values[0]; // 取回参数的第一个值        &#125;        //取所有值        @Override        public String[] getParameterValues(String name) &#123;            Map&lt;String, String[]&gt; parameterMap = getParameterMap();            String[] values = parameterMap.get(name);            return values;        &#125;    &#125;&#125;
&lt;filter&gt;  &lt;filter-name&gt;characterEncodingFilter&lt;/filter-name&gt;  &lt;filter-class&gt;org.springframework.web.filter.CharacterEncodingFilter&lt;/filter-class&gt;  &lt;init-param&gt;    &lt;param-name&gt;encoding&lt;/param-name&gt;    &lt;param-value&gt;utf-8&lt;/param-value&gt;  &lt;/init-param&gt;  &lt;init-param&gt;    &lt;param-name&gt;forceEncoding&lt;/param-name&gt;    &lt;param-value&gt;true&lt;/param-value&gt;  &lt;/init-param&gt;&lt;/filter&gt;
