&lt;?xml version=&quot;1.0&quot; encoding=&quot;UTF-8&quot; ?&gt;&lt;!DOCTYPE configuration        PUBLIC &quot;-//mybatis.org//DTD Config 3.0//EN&quot;        &quot;http://mybatis.org/dtd/mybatis-3-config.dtd&quot;&gt;&lt;configuration&gt;    &lt;settings&gt;        &lt;setting name=&quot;logImpl&quot; value=&quot;STDOUT_LOGGING&quot;/&gt;    &lt;/settings&gt;    &lt;typeAliases&gt;        &lt;package name=&quot;com.boogipop.pojo&quot;/&gt;    &lt;/typeAliases&gt;&lt;/configuration&gt;
package com.boogipop.pojo;import org.apache.ibatis.type.Alias;@Alias(&quot;Books&quot;)public class Books &#123;    private int bookID;    private String bookName;    private int bookCounts;    private String detail;    @Override    public String toString() &#123;        return &quot;Books&#123;&quot; +                &quot;bookID=&quot; + bookID +                &quot;, bookName=&#x27;&quot; + bookName + &#x27;\&#x27;&#x27; +                &quot;, bookCounts=&quot; + bookCounts +                &quot;, detail=&#x27;&quot; + detail + &#x27;\&#x27;&#x27; +                &#x27;&#125;&#x27;;    &#125;    public int getBookID() &#123;        return bookID;    &#125;    public void setBookID(int bookID) &#123;        this.bookID = bookID;    &#125;    public String getBookName() &#123;        return bookName;    &#125;    public void setBookName(String bookName) &#123;        this.bookName = bookName;    &#125;    public int getBookCounts() &#123;        return bookCounts;    &#125;    public void setBookCounts(int bookCounts) &#123;        this.bookCounts = bookCounts;    &#125;    public String getDetail() &#123;        return detail;    &#125;    public void setDetail(String detail) &#123;        this.detail = detail;    &#125;    public Books(int bookID, String bookName, int bookCounts, String detail) &#123;        this.bookID = bookID;        this.bookName = bookName;        this.bookCounts = bookCounts;        this.detail = detail;    &#125;&#125;
package com.boogipop.mapper;import com.boogipop.pojo.Books;import java.util.List;import java.util.Map;public interface BooksMapper &#123;//增加    Boolean AddBook(Books book);//删除    Boolean DelBook(int id);//修改    Boolean UpdateBook(Map&lt;Object,Object&gt; map);//查询所有    List&lt;Books&gt; SelectAllBooks();//查询某一本书    Books SelectBookById(int id);&#125;
&lt;?xml version=&quot;1.0&quot; encoding=&quot;UTF-8&quot; ?&gt;&lt;!DOCTYPE mapper PUBLIC &quot;-//mybatis.org//DTD mapper 3.0//EN&quot;        &quot;http://mybatis.org/dtd/mybatis-3-mapper.dtd&quot;&gt;&lt;mapper namespace=&quot;com.boogipop.mapper.BooksMapper&quot;&gt;    &lt;select id=&quot;SelectAllBooks&quot; resultType=&quot;Books&quot;&gt;        select * from books    &lt;/select&gt;    &lt;select id=&quot;SelectBookById&quot; resultType=&quot;Books&quot; parameterType=&quot;int&quot;&gt;        select * from books where id=#&#123;id&#125;    &lt;/select&gt;    &lt;insert id=&quot;AddBook&quot; parameterType=&quot;Books&quot;&gt;        insert into books(bookName,bookCounts,detail) values (#&#123;bookName&#125;,#&#123;bookCounts&#125;,#&#123;detail&#125;)    &lt;/insert&gt;    &lt;update id=&quot;UpdateBook&quot; parameterType=&quot;map&quot;&gt;        update books set bookName=#&#123;bookname&#125;,bookCounts=#&#123;bookcounts&#125;,detail=#&#123;detail&#125; where bookID=#&#123;id&#125;    &lt;/update&gt;    &lt;delete id=&quot;DelBook&quot; parameterType=&quot;int&quot;&gt;        delete from books where bookID=#&#123;id&#125;    &lt;/delete&gt;&lt;/mapper&gt;

