&lt;?xml version=&quot;1.0&quot; encoding=&quot;UTF-8&quot;?&gt;&lt;beans xmlns=&quot;http://www.springframework.org/schema/beans&quot;       xmlns:xsi=&quot;http://www.w3.org/2001/XMLSchema-instance&quot;       xmlns:context=&quot;http://www.springframework.org/schema/context&quot;       xsi:schemaLocation=&quot;http://www.springframework.org/schema/beans http://www.springframework.org/schema/beans/spring-beans.xsd http://www.springframework.org/schema/context https://www.springframework.org/schema/context/spring-context.xsd&quot;&gt;    &lt;context:property-placeholder location=&quot;db.properties&quot;/&gt;    &lt;context:component-scan base-package=&quot;com.boogipop.mapper&quot;/&gt;    &lt;context:component-scan base-package=&quot;com.boogipop.service&quot;/&gt;    &lt;bean id=&quot;datasource&quot; class=&quot;com.mchange.v2.c3p0.ComboPooledDataSource&quot;&gt;        &lt;property name=&quot;driverClass&quot; value=&quot;$&#123;jdbc.driver&#125;&quot;/&gt;        &lt;property name=&quot;jdbcUrl&quot; value=&quot;$&#123;jdbc.url&#125;&quot;/&gt;        &lt;property name=&quot;user&quot; value=&quot;$&#123;jdbc.username&#125;&quot;/&gt;        &lt;property name=&quot;password&quot; value=&quot;$&#123;jdbc.password&#125;&quot;/&gt;&lt;!--c3p0连接池私有属性--&gt;        &lt;property name=&quot;maxPoolSize&quot; value=&quot;30&quot;/&gt;        &lt;property name=&quot;minPoolSize&quot; value=&quot;10&quot;/&gt;&lt;!--        关闭连接池后不自动提交--&gt;        &lt;property name=&quot;autoCommitOnClose&quot; value=&quot;false&quot;/&gt;&lt;!--        响应超时时长--&gt;        &lt;property name=&quot;checkoutTimeout&quot; value=&quot;10000&quot;/&gt;&lt;!--        失败重连次数--&gt;        &lt;property name=&quot;acquireRetryAttempts&quot; value=&quot;2&quot;/&gt;    &lt;/bean&gt;    &lt;!-- 获取sqlsessionfactory--&gt;    &lt;bean id=&quot;sqlsessionfactory&quot; class=&quot;org.mybatis.spring.SqlSessionFactoryBean&quot;&gt;        &lt;!--绑定mybatis配置文件--&gt;        &lt;property name=&quot;dataSource&quot; ref=&quot;datasource&quot;/&gt;        &lt;property name=&quot;configLocation&quot; value=&quot;classpath:mybatis-config.xml&quot;/&gt;        &lt;property name=&quot;mapperLocations&quot; value=&quot;classpath:com/boogipop/mapper/*Mapper.xml&quot;/&gt;    &lt;/bean&gt;    &lt;!--加载mapper包中的所有接口，通过sqlSessionFactory获取sqlSession对象，然后创建所有的dao接口并存储在Spring容器中--&gt;    &lt;bean class=&quot;org.mybatis.spring.mapper.MapperScannerConfigurer&quot;&gt;        &lt;!--                                                       这里的value和上面sqlsessionfactory的id对应                     --&gt;        &lt;property name=&quot;sqlSessionFactoryBeanName&quot; value=&quot;sqlsessionfactory&quot;/&gt;        &lt;property name=&quot;basePackage&quot; value=&quot;com.boogipop.mapper&quot;/&gt;    &lt;/bean&gt;&lt;!--声明式事务配置--&gt;    &lt;bean class=&quot;org.springframework.jdbc.datasource.DataSourceTransactionManager&quot; id=&quot;transactionManager&quot;&gt;        &lt;!--注入数据源--&gt;        &lt;property name=&quot;dataSource&quot; ref=&quot;datasource&quot;/&gt;    &lt;/bean&gt;&lt;/beans&gt;
