package com.boogipop.service;import com.boogipop.pojo.Books;import java.util.List;import java.util.Map;public interface BookService &#123;        //增加        Boolean AddBook(Books book);        //删除        Boolean DelBook(int id);        //修改        Boolean UpdateBook(Map&lt;Object,Object&gt; map);        //查询所有        List&lt;Books&gt; SelectAllBooks();        //查询某一本书        Books SelectBookById(int id);&#125;
package com.boogipop.service;import com.boogipop.mapper.BooksMapper;import com.boogipop.pojo.Books;import org.springframework.beans.factory.annotation.Autowired;import org.springframework.stereotype.Component;import java.util.List;import java.util.Map;@Componentpublic class BookServiceImpl implements BookService&#123;    @Autowired    private BooksMapper booksMapper;    @Override    public Boolean AddBook(Books book) &#123;        return booksMapper.AddBook(book);    &#125;    @Override    public Boolean DelBook(int id) &#123;        return booksMapper.DelBook(id);    &#125;    @Override    public Boolean UpdateBook(Map&lt;Object, Object&gt; map) &#123;        return booksMapper.UpdateBook(map);    &#125;    @Override    public List&lt;Books&gt; SelectAllBooks() &#123;        return booksMapper.SelectAllBooks();    &#125;    @Override    public Books SelectBookById(int id) &#123;        return booksMapper.SelectBookById(id);    &#125;&#125;
&lt;?xml version=&quot;1.0&quot; encoding=&quot;UTF-8&quot;?&gt;&lt;beans xmlns=&quot;http://www.springframework.org/schema/beans&quot;       xmlns:xsi=&quot;http://www.w3.org/2001/XMLSchema-instance&quot;       xmlns:mvc=&quot;http://www.springframework.org/schema/mvc&quot;       xmlns:context=&quot;http://www.springframework.org/schema/context&quot;       xsi:schemaLocation=&quot;http://www.springframework.org/schema/beans        http://www.springframework.org/schema/beans/spring-beans.xsd         http://www.springframework.org/schema/context          https://www.springframework.org/schema/context/spring-context.xsd           http://www.springframework.org/schema/mvc            http://www.springframework.org/schema/mvc/spring-mvc.xsd&quot;&gt;&lt;!--将mapper整合进来--&gt;    &lt;import resource=&quot;ApplicationContext.xml&quot;/&gt;    &lt;import resource=&quot;mapperbean.xml&quot;/&gt;    &lt;import resource=&quot;servicebean.xml&quot;/&gt;&lt;!--包扫描--&gt;&lt;context:component-scan base-package=&quot;com.boogipop.controller&quot;/&gt;&lt;!-- 静态资源过滤--&gt;    &lt;mvc:default-servlet-handler/&gt;&lt;!--    注解驱动,静态资源过滤会导致注解驱动失效，因此必须补上--&gt;    &lt;mvc:annotation-driven/&gt;    &lt;bean class=&quot;org.springframework.web.servlet.view.InternalResourceViewResolver&quot; id=&quot;internalResourceViewResolver&quot;&gt;        &lt;!--        前缀--&gt;        &lt;property name=&quot;prefix&quot; value=&quot;/jsp/&quot;/&gt;        &lt;!--        后缀--&gt;        &lt;property name=&quot;suffix&quot; value=&quot;.jsp&quot;/&gt;    &lt;/bean&gt;&lt;/beans&gt;
到此树状图为：
SSM  ├─src    └─main        ├─java        │  └─com        │      └─boogipop        │          ├─controller        │          ├─mapper        │          ├─pojo        │          ├─service        │          └─utils        ├─resources        ├─test        └─webapp            ├─jsp            └─WEB-INF
SSM整合：查询书籍功能坑点注意首先是开启了静态资源过滤时，回导致默认的注解驱动失效，导致无法扫描到controller造成404，因此正确的配置应该改为：
&lt;?xml version=&quot;1.0&quot; encoding=&quot;UTF-8&quot;?&gt;&lt;beans xmlns=&quot;http://www.springframework.org/schema/beans&quot;       xmlns:xsi=&quot;http://www.w3.org/2001/XMLSchema-instance&quot;       xmlns:mvc=&quot;http://www.springframework.org/schema/mvc&quot;       xmlns:context=&quot;http://www.springframework.org/schema/context&quot;       xsi:schemaLocation=&quot;http://www.springframework.org/schema/beans        http://www.springframework.org/schema/beans/spring-beans.xsd         http://www.springframework.org/schema/context          https://www.springframework.org/schema/context/spring-context.xsd           http://www.springframework.org/schema/mvc            http://www.springframework.org/schema/mvc/spring-mvc.xsd&quot;&gt;&lt;!--将mapper整合进来--&gt;    &lt;import resource=&quot;ApplicationContext.xml&quot;/&gt;    &lt;import resource=&quot;mapperbean.xml&quot;/&gt;    &lt;import resource=&quot;servicebean.xml&quot;/&gt;&lt;!--包扫描--&gt;&lt;context:component-scan base-package=&quot;com.boogipop.controller&quot;/&gt;&lt;!-- 静态资源过滤--&gt;    &lt;mvc:default-servlet-handler/&gt;&lt;!--    注解驱动,静态资源过滤会导致注解驱动失效，因此必须补上--&gt;    &lt;mvc:annotation-driven/&gt;    &lt;bean class=&quot;org.springframework.web.servlet.view.InternalResourceViewResolver&quot; id=&quot;internalResourceViewResolver&quot;&gt;        &lt;!--        前缀--&gt;        &lt;property name=&quot;prefix&quot; value=&quot;/jsp/&quot;/&gt;        &lt;!--        后缀--&gt;        &lt;property name=&quot;suffix&quot; value=&quot;.jsp&quot;/&gt;    &lt;/bean&gt;&lt;/beans&gt;
然后还有一个坑点就是假如爆了500，Unsatisfiled错误，那就是说明我们的bean文件没有关联到一起，我们首先自定义了一个Controller：
package com.boogipop.controller;import com.boogipop.pojo.Books;import com.boogipop.service.BookService;import org.springframework.beans.factory.annotation.Autowired;import org.springframework.beans.factory.annotation.Qualifier;import org.springframework.stereotype.Controller;import org.springframework.ui.Model;import org.springframework.web.bind.annotation.RequestMapping;import java.util.List;@Controller@RequestMapping(&quot;/book&quot;)public class BookController &#123;    @Autowired    @Qualifier(&quot;bookServiceImpl&quot;)    private BookService bookService;    @RequestMapping(&quot;/allbooks&quot;)    public String booklist(Model model)&#123;        System.out.println(bookService);        List&lt;Books&gt; books = bookService.SelectAllBooks();        for (Books book : books) &#123;            System.out.println(book);        &#125;        model.addAttribute(&quot;msg&quot;,&quot;test&quot;);        return &quot;allbooks&quot;;    &#125;&#125;
在这里设置了私有属性bookservice，因此我们要将servicebean.xml和ApplicationContext.xml以及springmvc-servlet.xml文件整合在一起
踩完坑之后就开始完善:
package com.boogipop.controller;import com.boogipop.pojo.Books;import com.boogipop.service.BookService;import org.springframework.beans.factory.annotation.Autowired;import org.springframework.beans.factory.annotation.Qualifier;import org.springframework.stereotype.Controller;import org.springframework.ui.Model;import org.springframework.web.bind.annotation.RequestMapping;import java.util.List;@Controller@RequestMapping(&quot;/book&quot;)public class BookController &#123;    @Autowired    @Qualifier(&quot;bookServiceImpl&quot;)    private BookService bookService;    @RequestMapping(&quot;/allbooks&quot;)    public String booklist(Model model)&#123;        System.out.println(bookService);        List&lt;Books&gt; books = bookService.SelectAllBooks();        model.addAttribute(&quot;books&quot;,books);        return &quot;allbooks&quot;;    &#125;&#125;
