package com.boogipop.controller;import com.boogipop.pojo.Books;import com.boogipop.service.BookService;import org.springframework.beans.factory.annotation.Autowired;import org.springframework.beans.factory.annotation.Qualifier;import org.springframework.stereotype.Controller;import org.springframework.ui.Model;import org.springframework.web.bind.annotation.*;import org.springframework.web.servlet.HandlerInterceptor;import java.util.List;@Controller@RequestMapping(&quot;/book&quot;)public class BookController &#123;    @Autowired    @Qualifier(&quot;bookServiceImpl&quot;)    private BookService bookService;    @RequestMapping(&quot;/allbooks&quot;)    public String booklist(Model model)&#123;        List&lt;Books&gt; books = bookService.SelectAllBooks();        model.addAttribute(&quot;books&quot;,books);        return &quot;allbooks&quot;;    &#125;    @RequestMapping(&quot;/toaddbook&quot;)    public String toaddbook(Model model)&#123;        return &quot;addbook&quot;;    &#125;    @PostMapping(&quot;/addbook&quot;)    public String addbook(Model model,Books books) throws Exception &#123;        Boolean add = bookService.AddBook(books);        if(add)&#123;            System.out.println(&quot;add successfully&quot;);        &#125;        else&#123;            throw new Exception(&quot;添加错误&quot;);        &#125;        return &quot;redirect:/book/allbooks&quot;;    &#125;    @GetMapping(&quot;/toupdate&quot;)    public String toupdatebook(Model model,int id)&#123;        Books book = bookService.SelectBookById(id);        model.addAttribute(&quot;book&quot;,book);        return &quot;updatebook&quot;;    &#125;    @PostMapping(&quot;/updatebook&quot;)    public String updatebook(Books books)&#123;        System.out.println(books);        bookService.UpdateBook(books);        return &quot;redirect:/book/allbooks&quot;;    &#125;    @RequestMapping(&quot;/deletebook/&#123;id&#125;&quot;)    public String deletebook(@PathVariable int id)&#123;        bookService.DelBook(id);        return &quot;redirect:/book/allbooks&quot;;    &#125;    @RequestMapping(&quot;/querybook&quot;)    public String querybook(String queryBookName,Model model)&#123;        System.out.println(queryBookName);        List&lt;Books&gt; books = bookService.SelectBookByLike(queryBookName);        model.addAttribute(&quot;books&quot;,books);        return &quot;allbooks&quot;;    &#125;    @RequestMapping(&quot;/index&quot;)    public String index() &#123;        return &quot;index&quot;;    &#125;&#125;
